raw_commands:
{{ "\x1B@" }}
{{ "\x1Ba\x01" }}
{{ doc.company }}
POS CLOSING REPORT
{{ "\x1Ba\x00" }}
{{ "%-15s%33s"|format("Closing:", doc.name) }}
{{ "%-15s%33s"|format("Profile:", doc.pos_profile) }}
{{ "%-15s%33s"|format("Cashier:", doc.user) }}
{{ "%-15s%33s"|format("Start:", frappe.utils.format_datetime(doc.period_start_date, "yyyy-MM-dd hh:mm a") if doc.period_start_date else "") }}
{{ "%-15s%33s"|format("End:", frappe.utils.format_datetime(doc.period_end_date, "yyyy-MM-dd hh:mm a") if doc.period_end_date else "") }}
------------------------------------------------
{{ "%-15s%33s"|format("Invoices Count:", doc.pos_transactions|length) }}
{%- if doc.pos_transactions %}
{%- set first_inv = doc.pos_transactions[0].pos_invoice or doc.pos_transactions[0].sales_invoice or "" %}
{%- set last_inv = doc.pos_transactions[-1].pos_invoice or doc.pos_transactions[-1].sales_invoice or "" %}
{{ "%-15s%33s"|format("Inv From:", first_inv) }}
{{ "%-15s%33s"|format("Inv To:", last_inv) }}
{%- endif %}
------------------------------------------------
{{ "%-38s%10s"|format("Grand Total:", "%.2f"|format(doc.grand_total or 0)) }}
{{ "%-38s%10s"|format("Net Total:", "%.2f"|format(doc.net_total or 0)) }}
{{ "%-38s%10s"|format("Total Qty:", "%.2f"|format(doc.total_quantity or 0)) }}
------------------------------------------------
PAYMENT RECONCILIATION
{% for row in doc.payment_reconciliation %}{{ row.mode_of_payment }}
{{ "%-38s%10s"|format("  Open:", "%.2f"|format(row.opening_amount or 0)) }}
{{ "%-38s%10s"|format("  Expected:", "%.2f"|format(row.expected_amount or 0)) }}
{{ "%-38s%10s"|format("  Closing:", "%.2f"|format(row.closing_amount or 0)) }}
{{ "%-38s%10s"|format("  Difference:", "%.2f"|format(row.difference or 0)) }}
{% if not loop.last %}- - - - - - - - - - - - - - - - - - - - - - - -
{% endif %}{% endfor %}{% if doc.taxes %}------------------------------------------------
TAX SUMMARY
{% for row in doc.taxes %}{{ "%-38s%10s"|format(row.account_head[:30] ~ " (" ~ "%.2f"|format(row.rate or 0) ~ "%)", "%.2f"|format(row.amount or 0)) }}
{% endfor %}{% endif %}------------------------------------------------
FINAL SUMMARY
{% set total_expected = doc.payment_reconciliation | sum(attribute='expected_amount') -%}
{% set total_counted = doc.payment_reconciliation | sum(attribute='closing_amount') -%}
{% set summary_diff = total_counted - total_expected -%}
{{ "%-38s%10s"|format("Total Expected:", "%.2f"|format(total_expected or 0)) }}
{{ "%-38s%10s"|format("Total Counted:", "%.2f"|format(total_counted or 0)) }}
{{ "%-38s%10s"|format("Short / Over:", "%.2f"|format(summary_diff or 0)) }}
------------------------------------------------
{{ "%-15s%33s"|format("Printed At:", frappe.utils.format_datetime(frappe.utils.now_datetime(), "yyyy-MM-dd hh:mm a")) }}
{{ "%-15s%33s"|format("Printed By:", frappe.session.user) }}
------------------------------------------------
{{ "\x1Ba\x01" }}
End of Report


{{ "\x1DVA\x00" }}
